  { "id": "r025", "title": "The Innovator's Dilemma", "category": "Innovation & Entrepreneurship", "categoryId": "innovation-entrepreneurship", "author": "Clayton Christensen", "publisher": "Harvard Business Review Press", "publicationYear": "2013", "pageCount": 283, "isbn13": "9781422196021", "isbn10": "142219602X", "coverImage": "https://books.google.com/books/content?id=3JnBAgAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api", "infoLink": "https://books.google.com.eg/books?id=3JnBAgAAQBAJ&dq=intitle:%22The+Innovator%27s+Dilemma%22+inauthor:Clayton+Christensen&hl=&as_pt=BOOKS&source=gbs_api", "description": "An innovation classic. From Steve Jobs to Jeff Bezos, Clay Christensens work continues to underpin todays most innovative leaders and organizations. The bestselling classic on disruptive innovation, by renowned author Clayton M. Christensen. His work is cited by the worlds best-known thought leaders, from Steve Jobs to Malcolm Gladwell. In this classic bestsellerone of the most influential business books of all timeinnovation expert Clayton Christensen shows how even the most outstanding companies can do everything rightyet still lose market leadership. Christensen explains why most companies miss out on new waves of innovation. No matter the industry, he says, a successful company..." },
  { "id": "r026", "title": "The Brand Gap", "category": "Branding & Advertising", "categoryId": "branding-advertising", "author": "Marty Neumeier", "publisher": "New Riders Publishing", "publicationYear": "2003", "pageCount": 196, "isbn13": "9780735713307", "isbn10": "0735713308", "coverImage": "https://books.google.com/books/content?id=swb_IpkNNUsC&printsec=frontcover&img=1&zoom=1&source=gbs_api", "infoLink": "https://books.google.com.eg/books?id=swb_IpkNNUsC&dq=intitle:The+Brand+Gap+inauthor:Marty+Neumeier&hl=&as_pt=BOOKS&source=gbs_api", "description": "THE BRAND GAPis the first book to present a unified theory of brand. Whereas most books on branding are weighted toward either a strategic or creative approach, this book shows how both ways of thinking can unite to produce a charismatic brand-a brand that customers feel is essential to their lives. In an entertaining two-hour read youll learn:  a new definition of brand  the five essential disciplines of brand-building  how branding is changing the dynamics of competition  the three most powerful questions to ask about any brand  why collaboration is the key to brand-building  how design determines a customers experience  how to test brand concepts quickly and cheaply  the..." },
  { "id": "r027", "title": "Creative Confidence", "category": "Innovation & Entrepreneurship", "categoryId": "innovation-entrepreneurship", "author": "Tom Kelley & David Kelley", "publisher": "Crown Currency", "publicationYear": "2013", "pageCount": 306, "isbn13": "9780385349376", "isbn10": "0385349378", "coverImage": "https://books.google.com/books/content?id=Iu89yqLcl4AC&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api", "infoLink": "https://play.google.com/store/books/details?id=Iu89yqLcl4AC&source=gbs_api", "description": "IDEO founder and Stanford d.school creator David Kelley and his brother Tom Kelley, IDEO partner and the author of the bestselling The Art of Innovation, have written a powerful and compelling book on unleashing the creativity that lies within each and every one of us. Too often, companies and individuals assume that creativity and innovation are the domain of the \"creative types.\" But two of the leading experts in innovation, design, and creativity on the planet show us that each and every one of us is creative. In an incredibly entertaining and inspiring narrative that draws on countless stories from their work at IDEO, the Stanford d.school, and with many of the world's top companies..." },
  { "id": "r028", "title": "The Lean Startup", "category": "Innovation & Entrepreneurship", "categoryId": "innovation-entrepreneurship", "author": "Eric Ries", "publisher": "Crown Currency", "publicationYear": "2011", "pageCount": 337, "isbn13": "9780307887917", "isbn10": "030788791X", "coverImage": "https://books.google.com/books/content?id=tvfyz-4JILwC&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api", "infoLink": "https://play.google.com/store/books/details?id=tvfyz-4JILwC&source=gbs_api", "description": "Most startups fail. But many of those failures are preventable. The Lean Startup is a new approach being adopted across the globe, changing the way companies are built and new products are launched. Eric Ries defines a startup as an organization dedicated to creating something new under conditions of extreme uncertainty. This is just as true for one person in a garage or a group of seasoned professionals in a Fortune 500 boardroom. What they have in common is a mission to penetrate that fog of uncertainty to discover a successful path to a sustainable business. The Lean Startup approach fosters companies that are both more capital efficient and that leverage human creativity more..." },
